const headers = $json.headers || {};
const body = $json.body || {};
const data = body.data || {};
const expectedSecret = $env.N8N_WEBHOOK_SECRET;
const receivedSecret = headers['x-webhook-secret'] || headers['X-Webhook-Secret'];
const workflow = body.workflow || '';
const approvedWorkflows = new Set([
  'sympla_list_events',
  'sympla_lookup_participant_by_ticket',
  'sympla_checkin_participant'
]);

if (!expectedSecret) {
  throw new Error('N8N_WEBHOOK_SECRET is not configured in the n8n runtime environment.');
}

if (receivedSecret !== expectedSecret) {
  throw new Error('Invalid X-Webhook-Secret header.');
}

if (!$env.SYMPLA_S_TOKEN) {
  throw new Error('SYMPLA_S_TOKEN is not configured in the n8n runtime environment.');
}

if (!approvedWorkflows.has(workflow)) {
  throw new Error(`Unsupported workflow: ${workflow || 'missing workflow name'}.`);
}

if (workflow !== 'sympla_list_events' && (!data.event_id || !data.ticket_number)) {
  throw new Error(`${workflow} requires both event_id and ticket_number.`);
}

return [{
  json: {
    workflow,
    summary: body.summary || '',
    requiresConfirmation: Boolean(body.requiresConfirmation),
    confirmed: Boolean(data.confirmed),
    event_id: data.event_id || '',
    ticket_number: data.ticket_number || '',
    participant_id: data.participant_id || ''
  }
}];

const candidate = $json.data ?? $json;
const events = Array.isArray(candidate) ? candidate : (Array.isArray(candidate.data) ? candidate.data : []);
const preview = events.slice(0, 3).map((event) => ({
  id: event.id || event.event_id || '',
  name: event.name || event.title || event.event_name || 'Evento sem nome'
}));

return [{
  json: {
    workflow: 'sympla_list_events',
    status: 'success',
    action: 'listed_events',
    data: {
      totalEvents: events.length,
      events: preview
    },
    nextActionHint: events.length ? 'request_event_lookup_or_gated_checkin' : 'verify_the_sympla_account_has_events'
  }
}];

const request = $('Validate OpenClaw Request').item.json;
const participant = $json.data || $json.participant || $json;
const ticketNumber = participant.ticket_number || participant.ticket_num || request.ticket_number;
const participantName = [participant.first_name, participant.last_name].filter(Boolean).join(' ') || participant.name || participant.full_name || 'Participant found';
const checkinStatus = participant.checkin_status || participant.checked_in || participant.checkin || 'unknown';

return [{
  json: {
    workflow: 'sympla_lookup_participant_by_ticket',
    status: 'success',
    action: 'participant_lookup_completed',
    data: {
      event_id: request.event_id,
      ticket_number: ticketNumber,
      participant_name: participantName,
      checkin_status: checkinStatus
    },
    nextActionHint: 'offer_gated_checkin_if_operator_requests'
  }
}];

return [{
  json: {
    workflow: 'sympla_checkin_participant',
    status: 'confirmation_required',
    action: 'participant_checkin_blocked_pending_confirmation',
    data: {
      event_id: $json.event_id,
      ticket_number: $json.ticket_number,
      confirmed: false
    },
    nextActionHint: 'repeat_the_same_request_with_confirmed_true'
  }
}];

const request = $('Validate OpenClaw Request').item.json;
return [{
  json: {
    workflow: 'sympla_checkin_participant',
    status: 'success',
    action: 'participant_checkin_executed',
    data: {
      event_id: request.event_id,
      ticket_number: request.ticket_number,
      confirmed: true
    },
    nextActionHint: 'offer_participant_lookup_for_verification'
  }
}];
